/**
 * build-frontend-config.js
 *
 * Generates public/js/config.js with the correct API base URL.
 * Run this before deploying the frontend to Vercel.
 *
 * Usage:
 *   node scripts/build-frontend-config.js
 *   RENDER_URL=https://my-app.onrender.com node scripts/build-frontend-config.js
 */

const fs = require("fs");
const path = require("path");

const renderUrl = process.env.RENDER_URL || "";
const outputPath = path.join(__dirname, "../public/js/config.js");

const content = `// ─── Auto-generated by scripts/build-frontend-config.js ───────────────────
// Do NOT edit this file manually. Run: node scripts/build-frontend-config.js
// Generated: ${new Date().toISOString()}

(function () {
  "use strict";

  var isLocalhost =
    window.location.hostname === "localhost" ||
    window.location.hostname === "127.0.0.1";

  // In local dev the frontend and backend share the same origin (port 3000).
  // In production the frontend is on Vercel, so we need the Render backend URL.
  window.API_BASE_URL = isLocalhost
    ? "" // same-origin — no prefix needed
    : ${renderUrl ? `"${renderUrl}"` : `""`}; // Set RENDER_URL env var to inject your Render URL

  if (!isLocalhost && !window.API_BASE_URL) {
    console.warn(
      "[PDF Scanner] API_BASE_URL is not set. " +
      "Run: RENDER_URL=https://your-app.onrender.com node scripts/build-frontend-config.js"
    );
  }
})();
`;

fs.writeFileSync(outputPath, content, "utf8");
console.log(`✅ Generated: ${outputPath}`);
if (renderUrl) {
  console.log(`   API_BASE_URL → ${renderUrl}`);
} else {
  console.log("   API_BASE_URL → (empty — same-origin for local dev)");
  console.log(
    "   To set production URL: RENDER_URL=https://your-app.onrender.com node scripts/build-frontend-config.js"
  );
}
